import { createContext, useContext, useState, useEffect } from "react";

const AuthContext = createContext();
export const useAuth = () => useContext(AuthContext);

const USER_KEY = "demo_user";
export const USER_ROLES = {
  ADMIN: "ADMIN",
  CUSTOMER: "CUSTOMER",
};

const DEMO_ADMIN = {
  id: "admin-1",
  name: "System Admin",
  email: "admin@foodapp.demo",
  role: USER_ROLES.ADMIN,
  permissions: ["MANAGE_PRODUCTS", "MANAGE_ORDERS", "VIEW_REPORTS"],
  preferences: { newsletter: false, defaultPayment: "instapay", theme: "light" },
};

const DEMO_CUSTOMER = {
  id: "customer-1",
  name: "Demo Customer",
  email: "customer@foodapp.demo",
  role: USER_ROLES.CUSTOMER,
  phone: "",
  address: "",
  loyaltyPoints: 0,
  preferences: { newsletter: true, defaultPayment: "instapay", theme: "light" },
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [showLogin, setShowLogin] = useState(false);
  const [loginMode, setLoginMode] = useState("login");

  useEffect(() => {
    try {
      const raw = localStorage.getItem(USER_KEY);
      if (raw) setUser(JSON.parse(raw));
    } catch (e) {
      // ignore
    }
  }, []);

  const persistUser = (u) => {
    setUser(u);
    try {
      localStorage.setItem(USER_KEY, JSON.stringify(u));
    } catch (e) {}
  };

  const login = ({ email, role }) => {
    // static demo login that mirrors backend roles and models
    const normalizedRole = role === USER_ROLES.ADMIN ? USER_ROLES.ADMIN : USER_ROLES.CUSTOMER;
    let u = { email, role: normalizedRole };
    try {
      const saved = JSON.parse(localStorage.getItem(USER_KEY) || "null");
      if (saved && saved.email === email && saved.role === normalizedRole) u = saved;
    } catch (e) {}
    const roleDefaults = normalizedRole === USER_ROLES.ADMIN ? DEMO_ADMIN : DEMO_CUSTOMER;
    persistUser({
      ...roleDefaults,
      name: email ? email.split("@")[0] : roleDefaults.name,
      ...u,
    });
  };

  const signup = ({ name, email, phone, address }) => {
    const newUser = {
      id: `customer-${Date.now()}`,
      name: name || (email ? email.split("@")[0] : "user"),
      email: email || "user@demo",
      role: USER_ROLES.CUSTOMER,
      phone: phone || "",
      address: address || "",
      loyaltyPoints: 0,
      preferences: { newsletter: true, defaultPayment: "instapay", theme: "light" },
    };
    persistUser(newUser);
  };

  const logout = () => {
    setUser(null);
    try {
      localStorage.removeItem(USER_KEY);
    } catch (e) {}
  };

  const updateProfile = (updates) => {
    const next = { ...user, ...updates };
    persistUser(next);
  };

  const updatePreferences = (prefs) => {
    const next = { ...user, preferences: { ...(user?.preferences || {}), ...prefs } };
    persistUser(next);
  };

  const openLogin = (mode = "login") => { setLoginMode(mode); setShowLogin(true); };
  const closeLogin = () => setShowLogin(false);
  const hasRole = (role) => user?.role === role;

  // apply theme (dark/class) to document root when preferences change
  useEffect(() => {
    try {
      const theme = user?.preferences?.theme || "light";
      const root = document.documentElement;
      if (theme === "dark") {
        root.classList.add("dark");
      } else {
        root.classList.remove("dark");
      }
    } catch (e) {}
  }, [user?.preferences?.theme]);

  return (
    <AuthContext.Provider value={{ user, login, signup, logout, updateProfile, updatePreferences, isLoggedIn: !!user, hasRole, showLogin, loginMode, openLogin, closeLogin }}>
      {children}
    </AuthContext.Provider>
  );
};
